const documentText = $input.first().json.content;
const now = new Date();
const oneWeekAgo = new Date();
oneWeekAgo.setDate(oneWeekAgo.getDate() - 7);

// Finde alle Einträge mit Datum-Stamps (📅 DD.MM.YYYY, HH:MM)
const entryPattern = /📅\s(\d{2}\.\d{2}\.\d{4}),?\s(\d{2}:\d{2})[\s\S]*?(?=📅|$)/g;
const weeklyEntries = [];
let match;

while ((match = entryPattern.exec(documentText)) !== null) {
  const dateStr = match[1]; // DD.MM.YYYY
  const timeStr = match[2]; // HH:MM

  // Parse deutsches Datum
  const [day, month, year] = dateStr.split('.');
  const [hour, minute] = timeStr.split(':');
  const entryDate = new Date(year, month - 1, day, hour, minute);

  // Nur wenn innerhalb der letzten 7 Tage
  if (entryDate >= oneWeekAgo && entryDate <= now) {
    const entryText = match[0].trim();

    weeklyEntries.push({
      date: entryDate,
      dateStr: `${dateStr}, ${timeStr}`,
      content: entryText
    });
  }
}

// Sortiere chronologisch
weeklyEntries.sort((a, b) => a.date - b.date);

// Kombiniere für AI-Analyse
const weeklyText = weeklyEntries.map(entry => entry.content).join('\n\n---\n\n');

// Kalendarwoche berechnen
const getWeekNumber = (date) => {
  const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
  const dayNum = d.getUTCDay() || 7;
  d.setUTCDate(d.getUTCDate() + 4 - dayNum);
  const yearStart = new Date(Date.UTC(d.getUTCFullYear(),0,1));
  return Math.ceil((((d - yearStart) / 86400000) + 1)/7);
};

const currentWeek = getWeekNumber(now);

return [{
  json: {
    weeklyText: weeklyText,
    entryCount: weeklyEntries.length,
    weekNumber: currentWeek,
    dateRange: {
      from: oneWeekAgo.toLocaleDateString('de-CH'),
      to: now.toLocaleDateString('de-CH')
    },
    entries: weeklyEntries
  }
}];
